import pymysql
import functions_framework
from urllib.parse import unquote

@functions_framework.http
def search_api(request):
    # Extract request parameters
    request_args = request.args
    table = request_args.get('table', '')
    fields = request_args.get('fields', '*')
    limit = request_args.get('limit', '100')
    
    # Validate table name to prevent SQL injection
    allowed_tables = ['users', 'products', 'orders']
    if table not in allowed_tables:
        return {'error': 'Invalid table name'}, 400
    
    # Build base query
    query = f"SELECT {fields} FROM {table} WHERE 1=1"
    params = []
    
    # Process dynamic filters
    for key, value in request_args.items():
        if key in ['table', 'fields', 'limit']:
            continue
            
        # Validate field names to prevent SQL injection
        allowed_fields = ['name', 'email', 'status', 'created_at', 'price']
        if key not in allowed_fields:
            continue
            
        # Handle different operators
        if key.endswith('_gt'):
            field = key[:-3]
            query += f" AND `{field}` > %s"
            params.append(value)
        elif key.endswith('_lt'):
            field = key[:-3]
            query += f" AND `{field}` < %s"
            params.append(value)
        elif key.endswith('_eq'):
            field = key[:-3]
            query += f" AND `{field}` = %s"
            params.append(value)
        else:
            query += f" AND `{key}` LIKE %s"
            params.append(f"%{value}%")
    
    # Add limit
    try:
        limit_value = int(limit)
        if limit_value > 1000:
            limit_value = 1000
        query += f" LIMIT {limit_value}"
    except ValueError:
        query += " LIMIT 100"
    
    # Database connection
    connection = None
    try:
        connection = pymysql.connect(
            host='YOUR_CLOUD_SQL_CONNECTION_NAME',
            user='YOUR_USERNAME',
            password='YOUR_PASSWORD',
            database='YOUR_DATABASE',
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        with connection.cursor() as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()
            
        return {'results': results}
        
    except Exception as e:
        return {'error': str(e)}, 500
    finally:
        if connection:
            connection.close()